import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";
import { useEffect,useState } from "react";
export function PravljenjeRezervacije(){

        const[rezervacije,setRezervacije]=useState([]);
         const [sobe, setSobe] = useState([]);
         const [tipoviSobe,setTipSobe]=useState([]);


        useEffect(()=>{
          fetch("http://localhost:8080/reservations/getReservationStatus/pending")
          .then((res)=>res.json())
          .then((data) => {
        if (data && data.data && data.data.values) {
          setRezervacije(data.data.values);
        }
      }).catch((err) => console.error("Greška pri učitavanju rezervacija:", err));

        fetch("http://localhost:8080/rooms/all")
      .then((res) => res.json())
      
      .catch((err) => console.error("Greška pri učitavanju sobe:", err));

          fetch("http://localhost:8080/tip-sobe/all")
      .then((res) => res.json())
      .then((data) => {
        if (data && data.data && data.data.values) {
          setTipSobe(data.data.values);
        }

      })
        .catch((err) => console.error("Greška pri učitavanju tipa sobe:", err));

        console.log(tipoviSobe);
        console.log(sobe);
        console.log(rezervacije);

        },[])
    
    

    return(<>
   <div
        style={{
          minHeight: "100vh",
          display: "flex",
          flexDirection: "column",
          justifyContent: "space-between",
        }}
      >
        <NavBarRecepcionar />
  
        <div
          style={{
            backgroundImage: `url(${pattern})`,
            backgroundSize: "cover",
            backgroundPosition: "center",
            minHeight: "100vh",
            padding: "40px",
          }}
        >
            {rezervacije && <div>
                {
                    rezervacije.map(rezervacija=>
                        (<div>
                            
                        </div>)
                    )
                }
                
                </div>}

        </div>

        </div>

    <Footer />
    
    </>)
}
